15	type preClaimIntakeRewriteSnapshot struct {
16		DescriptionBytes int    `json:"description_bytes,omitempty"`
17		AcceptanceBytes  int    `json:"acceptance_bytes,omitempty"`
18		DescriptionSHA   string `json:"description_sha256,omitempty"`
19		AcceptanceSHA    string `json:"acceptance_sha256,omitempty"`
20	}
21	
22	type preClaimIntakeRewriteEventBody struct {
23		Rationale            string                        `json:"rationale,omitempty"`
24		ChangedFields        []string                      `json:"changed_fields,omitempty"`
25		Before               preClaimIntakeRewriteSnapshot `json:"before"`
26		After                preClaimIntakeRewriteSnapshot `json:"after"`
27		PreservationEvidence []string                      `json:"preservation_evidence,omitempty"`
28	}
29	
30	// Patterns for extracting explicit commitments from bead descriptions.
31	// A commitment is a durable anchor that must survive a replacement rewrite.
32	var (
33		reGoverningRef = regexp.MustCompile(`\b[A-Z]{2,6}-\d{3,}\b`)
34		reNamedTest    = regexp.MustCompile(`\bTest[A-Z]\w+\b`)
35		reFileLine     = regexp.MustCompile(`\b[\w/.-]+\.go:\d+\b`)
36		reDepID        = regexp.MustCompile(`\bddx-[0-9a-f]{8}\b`)
37	)
38	
39	var descriptionSectionHeaders = []string{
40		"PROBLEM", "ROOT CAUSE", "PROPOSED FIX", "NON-SCOPE", "NON SCOPE",
41		"CONTEXT", "PARENT", "DEPS", "DEPENDENCIES", "BACKGROUND",
42	}
43	
44	func isDescriptionSectionHeader(line string) bool {
45		upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(line), ":"))
46		for _, h := range descriptionSectionHeaders {
47			if upper == h {
48				return true
49			}
50		}
51		return false
52	}
53	
54	// extractNonScopeBullets returns normalized bullet text from the NON-SCOPE
55	// section of a bead description.
56	func extractNonScopeBullets(desc string) []string {
57		lines := strings.Split(desc, "\n")
58		var inNonScope bool
59		var result []string
60		for _, line := range lines {
61			trimmed := strings.TrimSpace(line)
62			upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(trimmed), ":"))
63			if upper == "NON-SCOPE" || upper == "NON SCOPE" {
64				inNonScope = true
65				continue
66			}
67			if inNonScope {
68				if trimmed == "" {
69					continue
70				}
71				if isDescriptionSectionHeader(trimmed) {
72					inNonScope = false
73					continue
74				}
75				bullet := strings.TrimLeft(trimmed, "-•*+# ")
76				bullet = normalizeWhitespace(bullet)
77				if bullet != "" {
78					result = append(result, bullet)
79				}
80			}
81		}
82		return result
83	}
84	
85	// extractDescriptionCommitments returns durable anchor strings that must be
86	// preserved across a description replacement rewrite:
87	//   - Governing artifact references (FEAT-010, ADR-023, etc.)
88	//   - Named test functions (TestFoo)
89	//   - File:line references (pkg/file.go:42)
90	//   - Dependency IDs (ddx-XXXXXXXX)
91	//   - NON-SCOPE section bullet points (prefixed with "non_scope:")
92	func extractDescriptionCommitments(desc string) []string {
93		seen := make(map[string]struct{})
94		var result []string
95		add := func(s string) {
96			if _, ok := seen[s]; !ok {
97				seen[s] = struct{}{}
98				result = append(result, s)
99			}
100		}
101		for _, m := range reGoverningRef.FindAllString(desc, -1) {
102			add(m)
103		}
104		for _, m := range reNamedTest.FindAllString(desc, -1) {
105			add(m)
106		}
107		for _, m := range reFileLine.FindAllString(desc, -1) {
108			add(m)
109		}
110		for _, m := range reDepID.FindAllString(desc, -1) {
111			add(m)
112		}
113		for _, bullet := range extractNonScopeBullets(desc) {
114			add("non_scope:" + bullet)
115		}
116		return result
117	}
118	
119	// validateDescriptionReplacement checks that all explicit commitments in the
120	// old description are preserved in the new description. It returns the list of
121	// preservation evidence entries recorded. An error is returned if any
122	// commitment is missing from the replacement.
123	func validateDescriptionReplacement(oldDesc, newDesc string) ([]string, error) {
124		commitments := extractDescriptionCommitments(oldDesc)
125		normNew := normalizeWhitespace(newDesc)
126		var evidence []string
127		for _, c := range commitments {
128			if strings.HasPrefix(c, "non_scope:") {
129				checkIn := strings.TrimPrefix(c, "non_scope:")
130				if !strings.Contains(normNew, checkIn) {
131					return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
132				}
133			} else {
134				if !strings.Contains(newDesc, c) {
135					return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
136				}
137			}
138			evidence = append(evidence, c)
139		}
140		return evidence, nil
141	}
142	
143	func applyPreClaimIntakeRewrite(store ExecuteBeadLoopStore, beadID, actor string, intake PreClaimIntakeResult, createdAt time.Time) error {
144		if store == nil {
145			return fmt.Errorf("pre-claim intake rewrite: bead store required")
146		}
147		if strings.TrimSpace(beadID) == "" {
148			return fmt.Errorf("pre-claim intake rewrite: bead id required")
149		}
150		if intake.normalizedOutcome() != PreClaimIntakeActionableButRewritten {
151			return fmt.Errorf("pre-claim intake rewrite: unexpected outcome %q", intake.normalizedOutcome())
152		}
153	
154		original, err := store.Get(beadID)
155		if err != nil {
156			return fmt.Errorf("pre-claim intake rewrite: load bead %s: %w", beadID, err)
157		}
158	
159		rewrite, before, after, preservation, err := validateAndApplyPreClaimIntakeRewrite(original, intake.Rewrite)
160		if err != nil {
161			return err
162		}
163	
164		if err := store.Update(beadID, func(b *bead.Bead) {
165			if rewrite.Description != "" {
166				b.Description = rewrite.Description
167			}
168			if rewrite.Acceptance != "" {
169				b.Acceptance = rewrite.Acceptance
170			}
171		}); err != nil {
172			return fmt.Errorf("pre-claim intake rewrite: update bead %s: %w", beadID, err)
173		}
174	
175		body, err := json.Marshal(preClaimIntakeRewriteEventBody{
176			Rationale:            strings.TrimSpace(intake.Detail),
177			ChangedFields:        rewrite.ChangedFields,
178			Before:               before,
179			After:                after,
180			PreservationEvidence: preservation,
181		})
182		if err != nil {
183			return fmt.Errorf("pre-claim intake rewrite: encode event: %w", err)
184		}
185	
186		summary := strings.Join(rewrite.ChangedFields, ",")
187		if summary == "" {
188			summary = "rewritten"
189		}
190		return store.AppendEvent(beadID, bead.BeadEvent{
191			Kind:      "intake-rewritten",
192			Summary:   summary,
193			Body:      string(body),
194			Actor:     actor,
195			Source:    "ddx agent execute-loop",
196			CreatedAt: createdAt.UTC(),
197		})
198	}
199	
200	func validateAndApplyPreClaimIntakeRewrite(original *bead.Bead, rewrite PreClaimIntakeRewrite) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
201		errOut := func(msg string, args ...any) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
202			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, fmt.Errorf(msg, args...)
203		}
204	
205		if original == nil {
206			return errOut("pre-claim intake rewrite: bead required")
207		}
208	
209		normalized := PreClaimIntakeRewrite{
210			Description:   strings.TrimSpace(rewrite.Description),
211			Acceptance:    strings.TrimSpace(rewrite.Acceptance),
212			ChangedFields: normalizePreClaimIntakeRewriteFields(rewrite.ChangedFields),
213		}
214		if len(normalized.ChangedFields) == 0 {
215			return errOut("pre-claim intake rewrite: missing changed_fields")
216		}
217	
218		allowed := map[string]struct{}{
219			"description": {},
220			"acceptance":  {},
221		}
222		for _, field := range normalized.ChangedFields {
223			if _, ok := allowed[field]; !ok {
224				return errOut("pre-claim intake rewrite: unsafe field %q", field)
225			}
226		}
227	
228		before := snapshotPreClaimIntakeRewrite(original.Description, original.Acceptance)
229	
230		var preservation []string
231		oldDescription := strings.TrimSpace(original.Description)
232		if hasString(normalized.ChangedFields, "description") {
233			if normalized.Description == "" {
234				return errOut("pre-claim intake rewrite: description rewrite missing")
235			}
236			if strings.EqualFold(strings.TrimSpace(normalized.Description), oldDescription) {
237				return errOut("pre-claim intake rewrite: description unchanged")
238			}
239			ev, err := validateDescriptionReplacement(oldDescription, normalized.Description)
240			if err != nil {
241				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, err
242			}
243			preservation = ev
244		} else if normalized.Description != "" {
245			return errOut("pre-claim intake rewrite: description supplied without changed_fields")
246		}
247	
248		oldAcceptance := strings.TrimSpace(original.Acceptance)
249		if hasString(normalized.ChangedFields, "acceptance") {
250			if normalized.Acceptance == "" {
251				return errOut("pre-claim intake rewrite: acceptance rewrite missing")
252			}
253			if strings.EqualFold(strings.TrimSpace(normalized.Acceptance), oldAcceptance) {
254				return errOut("pre-claim intake rewrite: acceptance unchanged")
255			}
256			if !acceptancePreservesCriteria(oldAcceptance, normalized.Acceptance) {
257				return errOut("pre-claim intake rewrite: acceptance criteria dropped or altered")
258			}
259		} else if normalized.Acceptance != "" {
260			return errOut("pre-claim intake rewrite: acceptance supplied without changed_fields")
261		}
262	
263		afterDescription := oldDescription
264		if containsString(normalized.ChangedFields, "description") {
265			afterDescription = normalized.Description
266		}
267		afterAcceptance := oldAcceptance
268		if containsString(normalized.ChangedFields, "acceptance") {
269			afterAcceptance = normalized.Acceptance
270		}
271		after := snapshotPreClaimIntakeRewrite(afterDescription, afterAcceptance)
272		return normalized, before, after, preservation, nil
273	}
274	
275	func snapshotPreClaimIntakeRewrite(description, acceptance string) preClaimIntakeRewriteSnapshot {
276		return preClaimIntakeRewriteSnapshot{
277			DescriptionBytes: len(description),
278			AcceptanceBytes:  len(acceptance),
279			DescriptionSHA:   hashText(description),
280			AcceptanceSHA:    hashText(acceptance),
281		}
282	}
283	
284	func hashText(text string) string {
285		sum := sha256.Sum256([]byte(text))
286		return hex.EncodeToString(sum[:])
287	}
288	
289	// acceptancePreservesCriteria returns true when the rewritten acceptance field
290	// ("after") contains all verifiable assertions from the original ("before").
291	//
292	// Structural reformatting — renumbering ("AC1." → "1."), reordering,
293	// normalising whitespace, or splitting one unnumbered sentence into several
294	// numbered criteria — is treated as preserving the criteria, not dropping them.
295	//
296	// A drop is detected only when the original had parseable numbered criteria and
297	// one or more of those criteria bodies are absent from the rewrite.
298	//
299	// When the original has no parseable numbered criteria (e.g. a single vague
300	// sentence), any rewrite that adds structured numbered criteria is accepted as
301	// an expansion; a rewrite that only rephrases the same prose content is checked
302	// by full-text containment.
303	func acceptancePreservesCriteria(before, after string) bool {
304		beforeCriteria := parseAcceptanceCriteria(before)
305		afterCriteria := parseAcceptanceCriteria(after)
306	
307		// If the original had no parseable numbered criteria, use a lenient path:
308		// any rewrite that introduces numbered criteria is an expansion (always
309		// accepted). If the rewrite is also unstructured, fall back to full-text
310		// containment on the normalised bodies.
311		if len(beforeCriteria) == 0 {
312			if len(afterCriteria) > 0 {
313				// Unstructured original → structured rewrite: expansion always allowed.
314				return true
315			}
316			normBefore := normalizeWhitespace(strings.TrimSpace(before))
317			normAfter := normalizeWhitespace(strings.TrimSpace(after))
318			if normBefore == "" {
319				return true
320			}
321			return strings.Contains(normAfter, normBefore)
322		}
323	
324		// Original had structured numbered criteria. Require each criterion body to
325		// appear in at least one criterion body of the rewrite (either verbatim or
326		// as a substring). The count check is a fast early-exit: if fewer criteria
327		// are present in the rewrite there must be a drop.
328		if len(afterCriteria) == 0 {
329			// Rewrite lost all structure — fall back to full-text containment of
330			// each criterion body inside the normalised rewrite text.
331			normAfter := normalizeWhitespace(strings.TrimSpace(after))
332			for _, criterion := range beforeCriteria {
333				if !strings.Contains(normAfter, criterion) {
334					return false
335				}
336			}
337			return true
338		}
339	
340		if len(afterCriteria) < len(beforeCriteria) {
341			return false
342		}
343	
344		for _, criterion := range beforeCriteria {
345			found := false
346			for _, candidate := range afterCriteria {
347				if strings.Contains(candidate, criterion) {
348					found = true
349					break
350				}
351			}
352			if !found {
353				return false
354			}
355		}
356		return true
357	}
358	
359	func parseAcceptanceCriteria(raw string) []string {
360		lines := strings.Split(raw, "\n")
361		out := make([]string, 0, len(lines))
362		for _, line := range lines {
363			if body, ok := parseAcceptanceCriterionBody(line); ok {
364				out = append(out, body)
365			}
366		}
367		return out
368	}
369	
370	// parseAcceptanceCriterionBody extracts the verifiable assertion text from a
371	// single acceptance criterion line. It recognises common bullet-prefix
372	// conventions used in bead acceptance fields:
373	//
374	//   - Pure numeric:  "1. body"  "42. body"
375	//   - AC-prefix:     "AC1. body"  "AC2. body"  (letters then digits before ".")
376	//   - Dash/bullet:   "- body"  "• body"  "* body"
377	//
378	// All these forms are normalised so that a reformat (e.g. "AC1." → "1.") does
379	// not appear to have dropped a criterion when the assertion text is identical.
380	func parseAcceptanceCriterionBody(line string) (string, bool) {
381		trimmed := strings.TrimSpace(line)
382		if trimmed == "" {
383			return "", false
384		}
385	
386		// Dash/star/bullet prefix: "- body", "* body", "+ body", "• body"
387		// The bullet character (•, U+2022) is multi-byte in UTF-8, so we use
388		// HasPrefix rather than a byte switch for that case.
389		if len(trimmed) >= 2 {
390			switch trimmed[0] {
391			case '-', '*', '+':
392				body := normalizeWhitespace(trimmed[1:])
393				if body != "" {
394					return body, true
395				}
396			}
397		}
398		if strings.HasPrefix(trimmed, "•") {
399			body := normalizeWhitespace(strings.TrimPrefix(trimmed, "•"))
400			if body != "" {
401				return body, true
402			}
403		}
404	
405		dot := strings.Index(trimmed, ".")
406		if dot <= 0 {
407			return "", false
408		}
409		prefix := trimmed[:dot]
410	
411		// Pure numeric: "1.", "42."
412		if allDigits(prefix) {
413			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
414			if body != "" {
415				return body, true
416			}
417			return "", false
418		}
419	
420		// AC-prefix: letters immediately followed by digits before the dot.
421		// Matches "AC1", "AC12", "A1", etc.
422		if isAlphaNumericBullet(prefix) {
423			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
424			if body != "" {
425				return body, true
426			}
427			return "", false
428		}
429	
430		return "", false
431	}
432	
433	// isAlphaNumericBullet returns true when s looks like a labelled-list prefix
434	// of the form letters+digits (e.g. "AC1", "AC12", "A1"). At least one letter
435	// and one digit must be present; the digits must all trail the letters.
436	func isAlphaNumericBullet(s string) bool {
437		if s == "" {
438			return false
439		}
440		// Find the split point where letters end and digits begin.
441		splitAt := -1
442		for i, r := range s {
443			isLetter := (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z')
444			isDigit := r >= '0' && r <= '9'
445			if !isLetter && !isDigit {
446				return false
447			}
448			if isDigit && splitAt == -1 {
449				splitAt = i
450			}
451			if isLetter && splitAt != -1 {
452				// letter after digit — not a clean ACN prefix
453				return false
454			}
455		}
456		// Must have at least one letter (splitAt > 0) and at least one digit.
457		return splitAt > 0
458	}
459	
460	func allDigits(s string) bool {
461		if s == "" {
462			return false
463		}
464		for _, r := range s {
465			if r < '0' || r > '9' {
466				return false
467			}
468		}
469		return true
470	}
471	
472	func normalizeWhitespace(s string) string {
473		return strings.Join(strings.Fields(strings.TrimSpace(s)), " ")
474	}
475	
476	func hasString(values []string, target string) bool {
477		for _, v := range values {
478			if v == target {
479				return true
480			}
481		}
482		return false
483	}
