3387	func trimDiagnosticPrefix(message, prefix string) string {
3388		message = strings.TrimSpace(message)
3389		prefix = strings.TrimSpace(prefix)
3390		if message == "" || prefix == "" {
3391			return message
3392		}
3393		for {
3394			next := strings.TrimSpace(strings.TrimPrefix(message, prefix+":"))
3395			if next == message {
3396				return message
3397			}
3398			message = next
3399		}
3400	}
