3402	func sleepWithContext(ctx context.Context, d time.Duration) error {
3403		if d <= 0 {
3404			return nil
3405		}
3406		timer := time.NewTimer(d)
3407		defer timer.Stop()
3408		select {
3409		case <-ctx.Done():
3410			return ctx.Err()
3411		case <-timer.C:
3412			return nil
3413		}
3414	}
