3416	// sleepOrWake sleeps for d unless ctx is cancelled or a wake signal arrives on
3417	// wakeCh. A wake signal returns nil (the loop re-scans the queue) so callers
3418	// like operatorPromptApprove can shorten the next-tick latency from a full
3419	// PollInterval to ~0. wakeCh may be nil — in which case this is equivalent to
3420	// sleepWithContext.
3421	func sleepOrWake(ctx context.Context, d time.Duration, wakeCh <-chan struct{}) error {
3422		if d <= 0 {
3423			return nil
3424		}
3425		if wakeCh == nil {
3426			return sleepWithContext(ctx, d)
3427		}
3428		timer := time.NewTimer(d)
3429		defer timer.Stop()
3430		select {
3431		case <-ctx.Done():
3432			return ctx.Err()
3433		case <-timer.C:
3434			return nil
3435		case <-wakeCh:
3436			return nil
3437		}
3438	}
